import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonSyntaxException;
import com.google.gson.reflect.TypeToken;
import com.google.gson.internal.bind.JsonTreeReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;

import java.lang.reflect.Method;

public class GsonFromJsonTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void fromJson_NullJson_ReturnsNull() throws Exception {
    TypeToken<String> typeToken = TypeToken.get(String.class);
    String result = gson.fromJson((JsonElement) null, typeToken);
    assertNull(result);
  }

  @Test
  public void fromJson_ValidJsonElement_DelegatesToFromJsonJsonTreeReader() throws Exception {
    JsonElement jsonElement = mock(JsonElement.class);
    TypeToken<String> typeToken = TypeToken.get(String.class);

    try (MockedConstruction<JsonTreeReader> mocked = mockConstruction(JsonTreeReader.class,
        (mock, context) -> {
          when(mock.peek()).thenReturn(null);
        })) {

      // Use reflection to invoke private fromJson(JsonTreeReader, TypeToken)
      Method fromJsonJsonTreeReaderMethod = Gson.class.getDeclaredMethod("fromJson", JsonTreeReader.class, TypeToken.class);
      fromJsonJsonTreeReaderMethod.setAccessible(true);

      // Spy on gson to verify delegation
      Gson spyGson = spy(gson);
      doReturn("expectedResult").when(spyGson).fromJson(any(JsonTreeReader.class), eq(typeToken));

      Object result = fromJsonJsonTreeReaderMethod.invoke(spyGson, new JsonTreeReader(jsonElement), typeToken);
      assertEquals("expectedResult", result);

      // Now test the public fromJson(JsonElement, TypeToken) method delegates correctly
      String actualResult = spyGson.fromJson(jsonElement, typeToken);
      assertEquals("expectedResult", actualResult);
    }
  }

  @Test
  public void fromJson_JsonTreeReaderThrowsJsonSyntaxException_Propagates() throws Exception {
    JsonElement jsonElement = mock(JsonElement.class);
    TypeToken<String> typeToken = TypeToken.get(String.class);

    Gson spyGson = spy(gson);

    doThrow(new JsonSyntaxException("syntax error"))
        .when(spyGson).fromJson(any(JsonTreeReader.class), eq(typeToken));

    JsonSyntaxException thrown = assertThrows(JsonSyntaxException.class, () -> {
      spyGson.fromJson(jsonElement, typeToken);
    });
    assertEquals("syntax error", thrown.getMessage());
  }

}
